export interface Instance {
  startOff: number
  endOff: number
  y: number
  flags: number
  mapq: number
  baseQuality: number
  insertSize: number
  pairOrient: number
  strand: number
  tagColor: number
  chainHasSupp: number
  readIndex: number
  edgeFlags: number
  readStartOff: number
  readEndOff: number
}

export function writeInstance(buf: ArrayBuffer, instanceIndex: number, inst: Instance) {
  const base = instanceIndex * 60
  const dv = new DataView(buf)
  dv.setUint32(base + 0, inst.startOff, true)
  dv.setUint32(base + 4, inst.endOff, true)
  dv.setUint32(base + 8, inst.y, true)
  dv.setUint32(base + 12, inst.flags, true)
  dv.setUint32(base + 16, inst.mapq, true)
  dv.setUint32(base + 20, inst.baseQuality, true)
  dv.setFloat32(base + 24, inst.insertSize, true)
  dv.setUint32(base + 28, inst.pairOrient, true)
  dv.setFloat32(base + 32, inst.strand, true)
  dv.setUint32(base + 36, inst.tagColor, true)
  dv.setUint32(base + 40, inst.chainHasSupp, true)
  dv.setUint32(base + 44, inst.readIndex, true)
  dv.setUint32(base + 48, inst.edgeFlags, true)
  dv.setUint32(base + 52, inst.readStartOff, true)
  dv.setUint32(base + 56, inst.readEndOff, true)
}
